const items = $input.all();

return items.map(item => {
  const data = item.json;

  // Проверяем обязательные поля
  if (data.chat_id === undefined || data.message_id === undefined) {
    console.warn('Missing required fields:', data);
    return {
      json: {
        error: 'Missing chat_id or message_id',
        data: data
      }
    };
  }

  // Убираем _debug из данных, если он есть
  const { _debug, ...dataWithoutDebug } = data;

  // SQL запрос с проверкой существования
  const query = `
    UPDATE telegram_messages
    SET 
      llm_processed = $1,
      llm_is_relevant = $2,
      updated_at = CURRENT_TIMESTAMP
    WHERE 
      chat_id = $3 
      AND message_id = $4
    RETURNING 
      id,
      (SELECT COUNT(*) FROM telegram_messages
       WHERE chat_id = $3 AND message_id = $4) > 0 as record_exists;
  `;

  const params = [
    dataWithoutDebug.llm_processed,      // $1
    dataWithoutDebug.llm_relevant,             // $2
    dataWithoutDebug.chat_id,                     // $3
    dataWithoutDebug.message_id                   // $4
  ];

  return {
    json: {
      // Для PostgreSQL
      query: query,
      params: params.join(','),

      // Для логирования (только нужные поля, без _debug)
      update_data: {
        chat_id: dataWithoutDebug.chat_id,
        message_id: dataWithoutDebug.message_id,
        llm_processed: dataWithoutDebug.llm_processed,
        llm_relevant: dataWithoutDebug.llm_relevant
      },
      action: 'update_llm_status'
    }
  };
});

const inputData = $input.all();

// Если структура точно такая: { json: { data: [...] } }
return inputData.map(item => {
  const filteredData = item.json.data.map(dataItem => ({
    chat_id: dataItem.chat_id,
    message_id: dataItem.message_id,
    user_id: dataItem.user_id,
    text: dataItem.text
  }));

  return {
    json: {
      data: filteredData
    }
  };
});

// Получаем входные данные
const items = $input.all();

// Создаем массив для результатов
let result = [];

// Проходим по всем элементам
items.forEach((item, index) => {
  // Проверяем, что data существует и является массивом
  if (item.json.data && Array.isArray(item.json.data)) {
    // Создаем новый массив для обработанных данных
    const processedData = [];

    // Обрабатываем каждый элемент в data
    item.json.data.forEach((dataItem, dataIndex) => {
      // Создаем новый объект с порядковым id
      const newItem = {
        id: processedData.length + 1, // Порядковый id с шагом 1
        text: dataItem.text || "" // Оставляем только текст
      };
      processedData.push(newItem);
    });

    // Создаем новый объект с сохраненной структурой
    result.push({
      data: processedData
    });
  }
});

// Возвращаем результат
return result.map(item => ({ json: item }));

const items = $input.all();
const originalData = items[0];
const llmResult = items[1];

// Сообщения (исходные)
const messages = (originalData?.json?.data || []);
// Результат LLM: массив объектов { llm_relevant, id }
const llmRows = (llmResult?.json?.output?.data || []);

// id -> llm_relevant
const relById = new Map();
for (const row of llmRows) {
  const id = Number(row?.id);
  const rel = Number(row?.llm_relevant);
  if (Number.isFinite(id) && (rel === 0 || rel === 1)) {
    relById.set(id, rel);
  }
}

const result = [];

// Связываем по порядку: i-ое сообщение соответствует id = i+1 (как у LLM)
for (let i = 0; i < messages.length; i++) {
  const message = messages[i];

  const id = i + 1;
  const llmRelevant = relById.has(id) ? relById.get(id) : 0; // fallback 0

  result.push({
    chat_id: message.chat_id,
    message_id: message.message_id,
    user_id: message.user_id,
    text: message.text,
    llm_processed: 1,
    llm_relevant: llmRelevant,
  });
}

return [
  {
    json: {
      data: result,
    },
  },
];

const items = $input.all();

if (!items.length) return [];

const row = items[0].json;
const raw = String(row["tg каналы chat_id"] ?? "").trim();

let target_chat_ids = [];

if (raw) {
  try {
    // Основной вариант: поле хранится как JSON-строка массива
    const parsed = JSON.parse(raw);

    if (Array.isArray(parsed)) {
      target_chat_ids = [...new Set(
        parsed
          .map(v => Number(v))
          .filter(v => Number.isFinite(v))
      )];
    }
  } catch (e) {
    // Запасной вариант: если вдруг придёт не JSON, а список через переносы/запятые
    target_chat_ids = [...new Set(
      raw
        .split(/[\r\n,]+/)
        .map(s => s.trim())
        .filter(Boolean)
        .map(s => Number(s))
        .filter(v => Number.isFinite(v))
    )];
  }
}

return [
  {
    json: {
      target_chat_ids,
    },
  },
];

const items = $input.all();

if (!items.length) {
  console.log('Нет входных данных');
  return [];
}

function parseTargetChatIds(value) {
  if (Array.isArray(value)) {
    return value
      .map(v => Number(v))
      .filter(v => Number.isFinite(v));
  }

  if (typeof value === 'string') {
    const raw = value.trim();
    if (!raw) return [];

    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        return parsed
          .map(v => Number(v))
          .filter(v => Number.isFinite(v));
      }
    } catch (e) {
      return raw
        .split(/[\r\n,]+/)
        .map(s => Number(String(s).trim()))
        .filter(v => Number.isFinite(v));
    }
  }

  return [];
}

// 1) Ищем item с target_chat_ids
let targetSet = null;
let targetItemIndex = -1;

for (let i = 0; i < items.length; i++) {
  const row = items[i]?.json ?? {};

  if (row.target_chat_ids !== undefined) {
    const parsed = parseTargetChatIds(row.target_chat_ids);
    targetSet = new Set(parsed);
    targetItemIndex = i;
    break;
  }
}

if (!targetSet || targetSet.size === 0) {
  console.log('Не найден или пуст target_chat_ids');
  return [];
}

const results = [];
const skippedChatIds = new Set();
const invalidChatIds = [];
const invalidMessageIds = [];

let processedCount = 0;
let skippedCount = 0;

// 2) Фильтруем все остальные items
for (let i = 0; i < items.length; i++) {
  if (i === targetItemIndex) continue;

  const row = items[i]?.json ?? {};

  if (row.chat_id === undefined || row.chat_id === null) {
    continue;
  }

  processedCount += 1;

  const chat_id = Number(row.chat_id);

  if (!Number.isFinite(chat_id)) {
    skippedCount += 1;
    invalidChatIds.push({
      item_index: i,
      chat_id_raw: row.chat_id ?? null,
      message_id: row.message_id ?? null,
    });
    continue;
  }

  const message_id =
    row.message_id === undefined || row.message_id === null || row.message_id === ''
      ? null
      : Number(row.message_id);

  if (row.message_id !== undefined && row.message_id !== null && row.message_id !== '' && !Number.isFinite(message_id)) {
    invalidMessageIds.push({
      item_index: i,
      chat_id,
      message_id_raw: row.message_id,
    });
  }

  if (targetSet.has(chat_id)) {
    results.push({
      json: {
        ...row,
        chat_id,
        message_id: Number.isFinite(message_id) ? message_id : row.message_id,
      },
    });
  } else {
    skippedCount += 1;
    skippedChatIds.add(chat_id);
  }
}

// 3) Логи
if (skippedChatIds.size > 0) {
  console.log(
    `Не взял сообщения из chat_id (не входят в target_chat_ids): ${[...skippedChatIds].join(', ')}`
  );
}

if (invalidChatIds.length > 0) {
  console.log(
    `Пропущены сообщения с некорректным chat_id: ${JSON.stringify(invalidChatIds)}`
  );
}

if (invalidMessageIds.length > 0) {
  console.log(
    `Сообщения с некорректным message_id оставлены как есть: ${JSON.stringify(invalidMessageIds)}`
  );
}

console.log(
  `Проверено сообщений: ${processedCount}; Взято: ${results.length}; Не взято: ${skippedCount}`
);

return results;

const items = $input.all();

// 1) Собираем исходные флаги по id
const sourceById = new Map();

// 2) Собираем предикты LLM
let llmData = [];

for (const item of items) {
  const data = item.json;

  // Исходные сообщения с флагами positive/negative
  if (data.id !== undefined && (data.positive === 1 || data.negative === 1)) {
    sourceById.set(Number(data.id), {
      positive: data.positive === 1 ? 1 : 0,
      negative: data.negative === 1 ? 1 : 0,
    });
  }

  // Результат LLM в формате { output: { data: [...] } }
  if (data.output && Array.isArray(data.output.data)) {
    llmData = data.output.data;
  }

  // На случай, если результат лежит в { data: [...] }
  if (
    Array.isArray(data.data) &&
    data.data.length > 0 &&
    data.data[0].id !== undefined &&
    data.data[0].llm_relevant !== undefined
  ) {
    llmData = data.data;
  }
}

if (!llmData.length) {
  throw new Error('Не найден массив с результатами LLM: output.data или data');
}

// 3) Объединяем по id
const result = llmData.map((pred) => {
  const id = Number(pred.id);
  const llmRelevant = Number(pred.llm_relevant ?? 0);
  const source = sourceById.get(id);

  if (!source) {
    throw new Error(`Не найден исходный item для id=${id}`);
  }

  const out = { id };

  if (source.positive === 1) {
    out.llm_relevant_positive = llmRelevant;
  } else if (source.negative === 1) {
    out.llm_relevant_negative = llmRelevant;
  } else {
    throw new Error(`Для id=${id} нет ни positive=1, ни negative=1`);
  }

  return { json: out };
});

return result;

const items = $input.all();

const result = [];

// Сначала positive
for (const item of items) {
  const data = item.json;

  const text = String(data.text_positive ?? '').trim();
  if (!text) continue;

  result.push({
    json: {
      id: data.ID ?? data.id ?? null,
      text,
      positive: 1,
    },
  });
}

// Потом negative
for (const item of items) {
  const data = item.json;

  const text = String(data.text_negative ?? '').trim();
  if (!text) continue;

  result.push({
    json: {
      id: data.ID ?? null,
      text,
      negative: 1,
    },
  });
}

return result;

const items = $input.all();

return items.map(item => {
  const data = item.json;

  return {
    json: {
      id: data.id ?? null,
      text: data.text ?? '',
    },
  };
});

const items = $input.all();

const result = {};

items.forEach((item) => {
  const data = item.json;
  const id = data.id ?? data.ID ?? null;

  if (id === null) {
    return;
  }

  result[`id_${id}`] = id;
  result[`text_${id}`] = data.text ?? '';
});

return [
  {
    json: result,
  },
];

const items = $input.all();

if (items.length < 2) {
  throw new Error('Ожидаю минимум 2 item: prompt и data');
}

const userPrompt = items[0].json.user_prompt;
const data = items[1].json.data;

return [
  {
    json: {
      prompt: userPrompt,
      data,
    },
  },
];

const items = $input.all();

if (!items.length) {
  throw new Error('Нет входных items');
}

const data = items[0].json.data;

if (!Array.isArray(data)) {
  throw new Error('Ожидается массив в items[0].json.data');
}

const byId = new Map();

for (const row of data) {
  const id = row.id;

  if (id === undefined || id === null) continue;

  if (!byId.has(id)) {
    byId.set(id, { id: Number(id) });
  }

  const out = byId.get(id);

  if (row.llm_relevant_positive !== undefined) {
    out.llm_relevant_positive = Number(row.llm_relevant_positive);
  }

  if (row.llm_relevant_negative !== undefined) {
    out.llm_relevant_negative = Number(row.llm_relevant_negative);
  }
}

return Array.from(byId.values()).map(row => ({ json: row }));

const items = $input.all();

if (items.length < 2) {
  throw new Error('Ожидаю минимум 2 item: prompt и data');
}

const userPrompt = items[0].json.user_prompt;
const data = items[1].json.data;

return [
  {
    json: {
      prompt: userPrompt,
      data,
    },
  },
];

const items = $input.all();

const results = [];

for (const item of items) {
  const data = item?.json?.data || [];

  for (const row of data) {
    const llm_relevant = Number(row?.llm_relevant);
    const llm_processed = Number(row?.llm_processed);

    results.push({
      json: {
        chat_id: row.chat_id,
        message_id: row.message_id,
        user_id: row.user_id,
        text: row.text,
        llm_processed,
        llm_relevant,
      },
    });
  }
}

return results;
